mkdir -p /tmp/sv-5e80618a81ee468e9ade617dcbbce46d/typed-meta && cd /tmp/sv-5e80618a81ee468e9ade617dcbbce46d/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta >/dev/null 2>&1 && cat > Program.cs << 'EOF'
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata: {personInfo.Type.Name}, kind = {personInfo.Kind}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
//    Simulate "unavailable" by using options with NO resolver.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };

if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found: {info!.Type.Name}");
}
else
{
    Console.WriteLine("Metadata not available — no exception thrown.");
}

record Person(string Name, int Age);
EOF
dotnet run

